from flask import Flask, request
import psycopg2

app = Flask(__name__)

@app.route('/query', methods=['POST'])
def query():
    data = request.get_json()
    
    table_name = data['table']
    columns = data.get('columns')
    filters = data.get('filters')

    conn = psycopg2.connect(database="your-database", user="username", password="password", host="127.0.0.1", port="5432")
    
    cur = conn.cursor()
    
    query = f'SELECT {", ".join(columns)} FROM {table_name}' if columns else f'SELECT * FROM {table_name}'
    
    if filters:
        conditions = [f'{k}=\'{v}\'' for k, v in filters.items()]
        query += f" WHERE {' AND '.join(conditions)}"
        
    cur.execute(query)

    rows = cur.fetchall()
    
    conn.close()

    return {'data': list(rows)}, 200

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=5000)